// Este fluxo NÃO executa otimizações - apenas calcula desvio para classificação.
// CONVENÇÃO: desvio POSITIVO = PIOR que a meta (vale para qualquer métrica).
const items = $input.all();
const returnData = [];

// Margem de contribuição padrão por modelo de negócio (fallback sem campo no Notion). break-even = 1/margem.
const MARGEM_PADRAO = {
  'E-commerce': 0.30, 'Ecommerce': 0.30,
  'SaaS': 0.80,
  'Infoproduto': 0.85, 'Infoprodutos': 0.85,
  'Serviços': 0.50, 'Servicos': 0.50, 'Serviço Local': 0.50,
  'B2B': 0.50, 'Lead': 0.50, 'Geração de Leads': 0.50
};
const MARGEM_FALLBACK = 0.30;
const MAIOR_MELHOR = ['ROAS', 'CTR', 'Taxa de Conversão', 'Taxa de Conversao'];

for (const item of items) {
  const data = item.json;
  const config = data.sop_config || {};
  const tipo = config.metric_principal || data.tipo_metrica || 'CPA';
  const isMaiorMelhor = MAIOR_MELHOR.includes(tipo);

  let v_d1 = Number(data.v_d1 ?? data.calc_context?.v_d1 ?? 0);
  let v_3d = Number(data.v_3d ?? data.calc_context?.v_3d ?? 0);
  let v_7d = Number(data.v_7d ?? data.calc_context?.v_7d ?? 0);
  if (v_d1 === 0 && v_3d === 0 && v_7d === 0) {
    try {
      const u = $("Code Unificar Períodos (D1, 3D, 7D)").first().json;
      v_d1 = Number(u.v_d1 || 0); v_3d = Number(u.v_3d || 0); v_7d = Number(u.v_7d || 0);
    } catch (e) {
      try {
        const c = $("Code Cálcula Métricas").first().json;
        v_d1 = Number(c.v_d1 || 0); v_3d = Number(c.v_3d || 0); v_7d = Number(c.v_7d || 0);
      } catch (e2) {}
    }
  }

  const margem = Number(
    data.clean_margem_contribuicao ||
    MARGEM_PADRAO[data.clean_modelo_negocio] ||
    MARGEM_PADRAO[data.clean_objetivo] ||
    MARGEM_FALLBACK
  );
  const break_even_roas = margem > 0 ? parseFloat((1 / margem).toFixed(2)) : null;

  let meta = Number(config.meta_valor || data.meta_valor || 0);
  if (tipo === 'ROAS' && (!meta || meta <= 0) && break_even_roas) {
    meta = break_even_roas;
  }

  if ((!meta || meta === 0) && v_d1 === 0 && v_3d === 0 && v_7d === 0) {
    returnData.push({ json: { ...data, analise_desvios: { error: "Meta não definida ou dados não encontrados" }, deviation_status: 'missing_data_for_calculation' } });
    continue;
  }

  const calcDesvio = (valor) => {
    if (meta === 0 || valor === 0) return 0;
    return isMaiorMelhor ? ((meta - valor) / meta) * 100 : ((valor - meta) / meta) * 100;
  };
  const calcTendencia = (v3, v7) => {
    if (!v7 || v7 === 0) return 0;
    return isMaiorMelhor ? ((v7 - v3) / v7) * 100 : ((v3 - v7) / v7) * 100;
  };

  const d1_res = calcDesvio(v_d1);
  const d3_res = calcDesvio(v_3d);
  const d7_res = calcDesvio(v_7d);
  const tend_proxy = parseFloat(calcTendencia(v_3d, v_7d).toFixed(2));

  // Prefere a tendência REAL (série diária BigQuery) quando disponível; senão usa a janela da API.
  const tendReal = (data.tendencia_real !== undefined && data.tendencia_real !== null) ? Number(data.tendencia_real) : null;
  const tendenciaFinal = tendReal !== null ? tendReal : tend_proxy;
  const tendenciaFonte = tendReal !== null ? (data.tendencia_metodo || 'bigquery') : 'janela_api';

  returnData.push({
    json: {
      ...data,
      v_d1, v_3d, v_7d,
      analise_desvios: {
        meta_aplicada: meta,
        tipo_metric: tipo,
        direcao: isMaiorMelhor ? 'maior_melhor' : 'menor_melhor',
        margem_contribuicao: margem,
        break_even_roas,
        d1: { valor: v_d1, desvio: parseFloat(d1_res.toFixed(2)) },
        d3: { valor: v_3d, desvio: parseFloat(d3_res.toFixed(2)) },
        d7: { valor: v_7d, desvio: parseFloat(d7_res.toFixed(2)) },
        tendencia_3d_vs_7d: tendenciaFinal,
        tendencia_proxy_api: tend_proxy,
        tendencia_fonte: tendenciaFonte,
        tendencia_n_dias: data.tendencia_n_dias ?? null
      },
      deviation_status: 'calculated_success'
    }
  });
}

return returnData;

// Classificação informativa (NÃO executa otimizações). Convenção: desvio positivo = pior.
// Inclui gate de significância estatística e limiares por objetivo (doc §3, §5.7, §7).
const items = $input.all();
const output = [];

// Gate de significância: abaixo destes mínimos no acumulado 7D não há base para julgar.
const MIN_CLICKS_7D = 100;
const MIN_CONV_7D = 10;

// Limite de desvio (%) para virar "Crítico", por objetivo. Fallback = 'default' (preserva 15).
const LIMITE_CRITICO = {
  'default': 15,
  'Conversão': 12, 'Conversões': 12, 'Vendas': 12,
  'Leads': 20, 'Geração de Leads': 20,
  'Tráfego': 30, 'Trafego': 30,
  'Reconhecimento': 40, 'Alcance': 40
};

for (const item of items) {
  const data = item.json;
  const analise = data.analise_desvios;
  const config = data.sop_config || {};

  if (!analise || !analise.d7) {
    output.push({ json: { ...data, final_status: "Sem Dados", final_score: 0, classe_score: "N/A", status_emoji: "⏳" } });
    continue;
  }

  // --- Volume 7D para o gate (defensivo entre Google e Meta) ---
  let clicks7d = Number(data.raw_clicks_7d ?? data.clicks_7d ?? 0);
  let conv7d = Number(data.raw_conversions_7d ?? data.conversions_7d ?? 0);
  if (clicks7d === 0 && conv7d === 0) {
    try {
      const m = $("HTTP Request Google Ontem (D7)").first().json.results?.[0]?.metrics || {};
      clicks7d = Number(m.clicks || 0);
      conv7d = Number(m.conversions || 0);
    } catch (e) {}
  }

  const tipo = analise.tipo_metric || config.metric_principal || 'CPA';
  const dependeConversao = ['CPA', 'ROAS', 'Taxa de Conversão', 'Taxa de Conversao'].includes(tipo);

  // Gate: sem volume mínimo, não classifica desempenho (evita decisão sobre ruído).
  if (clicks7d < MIN_CLICKS_7D || (dependeConversao && conv7d < MIN_CONV_7D)) {
    output.push({
      json: {
        ...data,
        final_status: "Dados Insuficientes",
        final_score: 50,
        classe_score: "Em aprendizado",
        status_emoji: "🔍",
        significancia: { clicks_7d: clicks7d, conversions_7d: conv7d, min_clicks: MIN_CLICKS_7D, min_conversoes: MIN_CONV_7D, suficiente: false }
      }
    });
    continue;
  }

  const d7 = analise.d7.desvio;
  const d1 = analise.d1.desvio;
  const tendencia = analise.tendencia_3d_vs_7d;

  const objetivo = data.clean_objetivo || data.objetivo || 'default';
  const limiteCritico = LIMITE_CRITICO[objetivo] || LIMITE_CRITICO['default'];

  // --- Classificação base por desvio 7D (positivo = pior) ---
  let status;
  if (d7 <= 0) status = "OK";
  else if (d7 <= limiteCritico) status = "Atenção";
  else status = "Crítico";

  // Ajuste por tendência (positivo = piorou)
  if (status === "OK" && tendencia > 10) status = "Atenção";
  // Ajuste por pico D-1
  if (status === "OK" && d1 > 30) status = "Atenção";

  // --- Score 0-100 ---
  let score = 100;
  score -= Math.min(Math.max(d7, 0) * 2, 40);
  if (tendencia > 0) score -= Math.min(tendencia, 30);
  if (d1 > 20) score -= 10;
  score = Math.max(Math.round(score), 0);

  let classeScore = "Crítico";
  if (score >= 80) classeScore = "Estável";
  else if (score >= 60) classeScore = "Atenção";
  else if (score >= 40) classeScore = "Instável";

  const emojiMap = { "OK": "✅", "Atenção": "⚠️", "Crítico": "🚨", "Sem Dados": "⏳", "Dados Insuficientes": "🔍" };

  output.push({
    json: {
      ...data,
      final_status: status,
      final_score: score,
      classe_score: classeScore,
      status_emoji: emojiMap[status] || "❓",
      significancia: { clicks_7d: clicks7d, conversions_7d: conv7d, suficiente: true }
    }
  });
}

return output;

const input = $input.first().json;

