// Função para calcular CPA ou ROAS
const calcularValor = (data, tipo) => {
  const metrics = data.results?.[0]?.metrics || {};
  const cost = Number(metrics.costMicros || 0) / 1000000;
  const conv = Number(metrics.conversions || 0);
  const val = Number(metrics.conversionsValue || 0);

  if (tipo === "ROAS") return cost > 0 ? val / cost : 0;
  return conv > 0 ? cost / conv : 0;
};

// Item #7: extrai metricas brutas para BigQuery
const extractRaw = (data) => {
  const m = data.results?.[0]?.metrics || {};
  const costMicros = Number(m.costMicros || m.cost_micros || 0);
  return {
    cost: costMicros / 1_000_000,
    costMicros,
    clicks: Number(m.clicks || 0),
    conversions: Number(m.conversions || 0),
    conversionsValue: Number(m.conversionsValue || m.conversions_value || 0),
