  const metricaJanela = (cost, conv, clicks, impr, rev) => {
    if (tipo === 'ROAS') return cost > 0 ? rev / cost : null;
    if (tipo === 'CPC') return clicks > 0 ? cost / clicks : null;
    if (tipo === 'CTR') return impr > 0 ? (clicks / impr) * 100 : null;
    if (tipo === 'Taxa de Conversão') return clicks > 0 ? (conv / clicks) * 100 : null;
    return conv > 0 ? cost / conv : null;        // CPA / CPL
