  if (nDias >= 4) {
    const recente = metricaJanela(num(r.cost_3), num(r.conv_3), num(r.clicks_3), num(r.impr_3), num(r.rev_3));
    const anterior = metricaJanela(num(r.cost_prev3), num(r.conv_prev3), num(r.clicks_prev3), num(r.impr_prev3), num(r.rev_prev3));
    if (recente != null && anterior != null && anterior > 0) {
