    });
  }

  const metrics = calculatePaidMediaMetrics(raw7, raw30);
  const valorReal = metricValue(metrics, tipoMetrica);

  let statusMeta = 'No Alvo ?';
  if (metaValor > 0) {
    const isLowerBetter = lowerIsBetter(tipoMetrica);
    if (isLowerBetter) {
      statusMeta = valorReal <= metaValor ? 'No Alvo ✅' : 'Acima da Meta 🚨';
    } else {
      statusMeta = valorReal >= metaValor ? 'No Alvo ✅' : 'Abaixo da Meta 📉';
    }
  }

  output.push({
    json: {
      ...data,
      valor_real: round(valorReal, 2),
      meta_estabelecida: metaValor,
      status_meta: statusMeta,
      orcamento_diario: round(raw7.budget, 2),
      aprendizado: String(raw7.status || 'ESTÁVEL').replace(/_/g, ' '),
      opt_score: round(raw7.optScore, 2),

      ...metrics,

      raw_cost_7d: metrics.cost_7d,
      raw_cost_30d: metrics.cost_30d,
      raw_cost_micros_7d: round(raw7.costMicros, 0),
      raw_cost_micros_30d: round(raw30.costMicros, 0),
      raw_clicks_7d: raw7.clicks,
      raw_clicks_30d: raw30.clicks,
      raw_impressions_7d: raw7.impressions,
      raw_impressions_30d: raw30.impressions,
      raw_conversions_7d: metrics.conversions_7d,
      raw_conversions_30d: metrics.conversions_30d,
      raw_conversions_value_7d: metrics.revenue_7d,
      raw_conversions_value_30d: metrics.revenue_30d,

      metricas_calculadas: {
        d7: {
          custo: metrics.cost_7d,
          cliques: metrics.clicks_7d,
          impressoes: metrics.impressions_7d,
          conversoes: metrics.conversions_7d,
          receita: metrics.revenue_7d,
          cpc: metrics.cpc_7d,
          cpa: metrics.cpa_7d,
          cpl: metrics.cpl_7d,
          ctr: metrics.ctr_7d,
          cpm: metrics.cpm_7d,
          cvr: metrics.cvr_7d,
          roas: metrics.roas_7d
        },
        d30: {
          custo: metrics.cost_30d,
          cliques: metrics.clicks_30d,
          impressoes: metrics.impressions_30d,
          conversoes: metrics.conversions_30d,
          receita: metrics.revenue_30d,
          cpc: metrics.cpc_30d,
          cpa: metrics.cpa_30d,
          cpl: metrics.cpl_30d,
          ctr: metrics.ctr_30d,
          cpm: metrics.cpm_30d,
          cvr: metrics.cvr_30d,
          roas: metrics.roas_30d
        }
      }
    }
  });
}

return output;

// Colapsa multiplos itens do trigger em 1 (o fetch de anuncios deve rodar uma vez).
const items = $input.all();
const ctx = items.find(i => i.json && i.json.source_execution_id) || items[0] || { json: {} };
return [ctx];

const seen = new Set();
return $input.all().filter(it => {
  const id = it.json.id;
  if (!id || seen.has(id)) return false;
  seen.add(id);
  return true;
});
